  n_fac:      Inputs.range([2, 5], {step: 1, value: 3,
                label: "Number of factors to study"}),
  a_name:     Inputs.text({label: "Factor A — name",   value: "Eco badge",    width: 160}),
  a_levels:   Inputs.select([2, 3, 4], {label: "Factor A — levels", value: 3}),
  b_name:     Inputs.text({label: "Factor B — name",   value: "Price level",  width: 160}),
  b_levels:   Inputs.select([2, 3, 4], {label: "Factor B — levels", value: 3}),
  c_name:     Inputs.text({label: "Factor C — name",   value: "Framing",      width: 160}),
  c_levels:   Inputs.select([2, 3, 4], {label: "Factor C — levels", value: 3}),
  d_name:     Inputs.text({label: "Factor D — name",   value: "Source cred.", width: 160}),
  d_levels:   Inputs.select([2, 3, 4], {label: "Factor D — levels", value: 2}),
  e_name:     Inputs.text({label: "Factor E — name",   value: "Ad copy",      width: 160}),
  e_levels:   Inputs.select([2, 3, 4], {label: "Factor E — levels", value: 2}),
