                label: "Participants per cell"}),
})







ls_state = {
  const nf   = ls_config.n_fac
  const defs = [
    {name: ls_config.a_name || "Factor A", levels: +ls_config.a_levels},
    {name: ls_config.b_name || "Factor B", levels: +ls_config.b_levels},
    {name: ls_config.c_name || "Factor C", levels: +ls_config.c_levels},
    {name: ls_config.d_name || "Factor D", levels: +ls_config.d_levels},
    {name: ls_config.e_name || "Factor E", levels: +ls_config.e_levels},
  ]
  const facs = defs.slice(0, nf)
  const maxL = Math.max(...facs.map(f =&gt; f.levels))

  const cells = []
  for (let r = 0; r &lt; maxL; r++) {
    for (let c = 0; c &lt; maxL; c++) {
      const cell = {row: r + 1, col: c + 1}
      facs.forEach((fac, k) =&gt; {
        cell["lv" + k]    = ((r + c + k) % fac.levels) + 1
        cell["short" + k] = (fac.name || ("F" + (k+1))).substring(0, 4) + "\u202f" +
                             (((r + c + k) % fac.levels) + 1)
      })
      cell.fa_label     = "Level\u00a0" + (((r + c) % facs[0].levels) + 1)
      cell.other_labels = facs.slice(1)
        .map((f, i) =&gt; (f.name || ("F" + (i+2))).substring(0, 4) + "\u202f" +
                        (((r + c + i + 1) % f.levels) + 1))
        .join("  ")
      cells.push(cell)
    }
  }

  const full_factorial = facs.reduce((acc, f) =&gt; acc * f.levels, 1)
  const ls_cells       = maxL * maxL
  const n_per_cell     = +ls_config.n_per_cell

  return {facs, cells, maxL, full_factorial, ls_cells,
          total_n: ls_cells * n_per_cell, n_per_cell, nf}
}







